use std::sync::atomic::{AtomicBool, Ordering};

pub fn spin_lock(lock: &AtomicBool) {
    while !lock.compare_and_swap(false, true, Ordering::Acquire) {}
}

pub fn spin_unlock(lock: &AtomicBool) {
    lock.store(false, Ordering::Release);
}

